headerButton.customFunction:
let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get('customDialog'));
let entityService = $injector.get(widgetContext.servicesMap.get('entityService'));
let attributeService = $injector.get(widgetContext.servicesMap.get('attributeService'));
let entityRelationService = $injector.get(widgetContext.servicesMap.get('entityRelationService'));
let entityGroupService = $injector.get(widgetContext.servicesMap.get('entityGroupService'));

let dialogTitle = "Create Level Sensor";
let createEntity = true;

let attributeKeys = [];
let additionalAttributes = [ ];
let additionalTelemetry = [ ];

openEntityDialog();

function openEntityDialog() {
  customDialog.customDialog(htmlTemplate, EntityDialogController).subscribe();
}

function EntityDialogController(instance) {
  let vm = instance;

  const currentUser = widgetContext.currentUser;

  if (createEntity) {
    vm.dialogTitle = dialogTitle;
  } else {
    vm.dialogTitle = dialogTitle.replaceAll('${entityName}', entityName);
  }

  vm.submitTitle = createEntity ? 'Create' : 'Save';

  vm.entityFormGroup = vm.fb.group({
    entityFields: vm.fb.group({
      name: [null, [vm.validators.required]]
    }),

  });



  if (attributeKeys.length) {
    vm.entityFormGroup.addControl('attributes',
      vm.fb.group({

      })
    );
  }

  vm.save = function() {
    vm.entityFormGroup.markAsPristine();
    saveEntity().subscribe(
      function (entity) {
        widgetContext.rxjs.forkJoin([
          saveAttributes(entity.id),
          saveTelemetry(entity.id),
          createRelations(entity.id),
          addToEntityGroups(entity.id)
        ]).subscribe(
          function () {
            widgetContext.updateAliases();
            vm.dialogRef.close(null);
          }
        );
      }
    );
  };

  vm.cancel = function() {
    vm.dialogRef.close(null);
  };

  if (!createEntity) {
    loadEntity();
  }

  function saveEntity() {
    const entityFields = vm.entityFormGroup.get('entityFields').value;
    let entity;
    if (createEntity) {
      entity = entityFields;
      let entityType = "DEVICE";
      let entitySubType = "LevelSensor";
      let entityOwner = "";
      entity.id = {
        entityType: entityType
      };


      if (entitySubType) {
        entity.type = entitySubType;
      }

      if (entityOwner) {
        let stateParams = widgetContext.stateController.getStateParams();
        if (stateParams[entityOwner]) {
          stateParams = stateParams[entityOwner];
        }
        let ownerId = stateParams.entityId;
        if (ownerId && ownerId.entityType === 'CUSTOMER') {
          entity.customerId = ownerId;
        }
      }
      if (!entity.customerId && widgetContext.currentUser.authority === 'CUSTOMER_USER') {
        entity.customerId = {id: widgetContext.currentUser.customerId, entityType: 'CUSTOMER'};
      }
      if (entityType === 'USER') {
        if (entity.customerId) {
          entity.authority = 'CUSTOMER_USER';
        } else {
          entity.authority = 'TENANT_ADMIN';
        }
      }
    } else {
      entity = {...vm.entity, ...entityFields};
    }
    return entityService.saveEntity(entity);
  }

  function saveAttributes(entityId) {
    if (attributeKeys.length || additionalAttributes.length) {
      let attributes = attributeKeys.length ? vm.entityFormGroup.get('attributes').value : [];
      let attributesArray = [];
      for (let key in attributes) {
        if (attributes[key] !== null) {
          attributesArray.push({key: key, value: attributes[key]});
        }
      }
      if (additionalAttributes.length) {
        additionalAttributes.forEach(attribute => {
          attributesArray.push({key: attribute.key, value: attribute.value});
        })
      }
      if (attributesArray.length > 0) {
        return attributeService.saveEntityAttributes(entityId, "SERVER_SCOPE", attributesArray);
      } else {
        return widgetContext.rxjs.of([]);
      }
    } else {
      return widgetContext.rxjs.of([]);
    }
  }

    function saveTelemetry(entityId) {
      if (additionalTelemetry.length) {
        let telemetryArray = [];
        additionalTelemetry.forEach(telemetry => {
          telemetryArray.push({key: telemetry.key, value: telemetry.value});
        })
        return attributeService.saveEntityTimeseries(entityId, "LATEST_TELEMETRY", telemetryArray);
      } else {
        return widgetContext.rxjs.of([]);
      }
    }

  function createRelations(entityId) {
    let singleEntityId;
    for (const value of Object.values(widgetContext.aliasController.entityAliases)) {
      if (value.filter.type === 'singleEntity') {
        singleEntityId = value.filter.singleEntity ?? null;
      }
    }

    if (createEntity) {
      let createRelationsObservables = [];

      let createRelations = [{"fromStateEntity":"singleEntity","type":"WaterTankToLevelSensor"}];
      if (createRelations && createRelations.length) {
        let stateParams = widgetContext.stateController.getStateParams();
        for (let createRelation of createRelations) {
          let fromEntityId = null;
          if (createRelation.fromStateEntity === 'singleEntity' && singleEntityId) {
            fromEntityId = singleEntityId;
          } else if (createRelation.fromStateEntity && stateParams[createRelation.fromStateEntity]) {
            fromEntityId = stateParams[createRelation.fromStateEntity].entityId;
          } else {
            fromEntityId = stateParams.entityId;
          }
          if (!fromEntityId && createRelation.fromStateEntity === 'currentCustomer') {
            fromEntityId = {id: currentUser.customerId, entityType: "CUSTOMER" };
          }
          if (fromEntityId && fromEntityId.id && fromEntityId.entityType) {
            let relation = {
              type: createRelation.type,
              typeGroup: 'COMMON',
              from: fromEntityId,
              to: entityId
            };
            createRelationsObservables.push(entityRelationService.saveRelation(relation));
          }
        }
      }


      if (createRelationsObservables.length) {
        return widgetContext.rxjs.forkJoin(createRelationsObservables);
      } else {
        return widgetContext.rxjs.of([]);
      }
    } else {
      return widgetContext.rxjs.of([]);
    }
  }

  function addToEntityGroups(entityId) {
    if (createEntity) {
      let addToGroupObservables = [];
      let targetEntityGroups = ["LevelSensor"];

      let entityOwner = "";
      let ownerId;
      if (entityOwner) {
        let stateParams = widgetContext.stateController.getStateParams();
        if (stateParams[entityOwner]) {
            stateParams = stateParams[entityOwner];
        }
        ownerId = stateParams.entityId;
      }
      if (targetEntityGroups && targetEntityGroups.length) {
        for (let targetEntityGroup of targetEntityGroups) {
          addToGroupObservables.push(getOrCreateEntityGroupByName(targetEntityGroup, entityId.entityType, ownerId).pipe(
            widgetContext.rxjs.switchMap((group) => {
              if (group) {
                return entityGroupService.addEntityToEntityGroup(group.id.id, entityId.id);
              } else {
                return widgetContext.rxjs.of(null);
              }
            })
          ));
        }
      }
      if (addToGroupObservables.length) {
        return widgetContext.rxjs.forkJoin(addToGroupObservables);
      } else {
        return widgetContext.rxjs.of([]);
      }
    } else {
      return widgetContext.rxjs.of([]);
    }
  }

  function loadEntity() {
    entityService.getEntity(entityId.entityType, entityId.id).subscribe(
      function(entity) {
        vm.entity = entity;
        vm.entityFormGroup.get('entityFields').patchValue(entity);
        if (attributeKeys.length) {
          attributeService.getEntityAttributes(entityId, 'SERVER_SCOPE', attributeKeys).subscribe(
            function (attributes) {
              let entityAttributes = {};
              for (var i = 0; i < attributes.length; i++) {
                entityAttributes[attributes[i].key] = attributes[i].value;
              }
              vm.entityFormGroup.get('attributes').patchValue(entityAttributes);
            }
          );
        }
      }
    );
  }

  function getOrCreateEntityGroupByName(groupName, groupType, ownerId) {
    var entityGroupsPageLink = widgetContext.pageLink(10, 0, groupName);
    let findEntyGroup$;
    if (ownerId) {
      findEntyGroup$ = entityGroupService.getEntityGroupsByOwnerIdAndPageLink(ownerId.entityType, ownerId.id, groupType, entityGroupsPageLink, {ignoreLoading: true});
    } else {
      findEntyGroup$ = entityGroupService.getEntityGroupsByPageLink(entityGroupsPageLink, groupType, {ignoreLoading: true});
    }
    return findEntyGroup$.pipe(
      widgetContext.rxjs.switchMap((data) => {
        if (data.data.length) {
          const findGroup = data.data.find((group) => group.name === groupName);
          if (findGroup) {
            return widgetContext.rxjs.of(findGroup);
          }
        }
        const entityGroup = {
          name: groupName,
          type: groupType,
        }
        if (ownerId) {
          entityGroup.ownerId = ownerId;
        }
        return entityGroupService.saveEntityGroup(entityGroup, {ignoreLoading: true}).pipe(
          widgetContext.rxjs.catchError(() => widgetContext.rxjs.of(null))
        );
      })
    );
  }
}

