let $injector = widgetContext.$scope.$injector;
let dialogs = $injector.get(widgetContext.servicesMap.get('dialogs'));
let deleteEntityTitle = "Delete Level Sensor '${entityName}'";
let deleteEntityPrompt = "Are you sure you want to delete the level sensor '${entityName}'?";

deleteEntityTitle = deleteEntityTitle.replaceAll('${entityName}', entityName);
deleteEntityPrompt = deleteEntityPrompt.replaceAll('${entityName}', entityName);

openDeleteEntityDialog();

function openDeleteEntityDialog() {
  dialogs.confirm(deleteEntityTitle, deleteEntityPrompt, 'Cancel', 'Delete').subscribe(
    function(result) {
      if (result) {
        deleteEntity(entityId);
      }
    }
  );
}

function deleteEntity(entityId) {
  let deleteObservable = null;
  switch (entityId.entityType) {
    case 'DEVICE':
      let deviceService = $injector.get(widgetContext.servicesMap.get('deviceService'));
      deleteObservable = deviceService.deleteDevice(entityId.id);
      break;
    case 'ASSET':
      let assetService = $injector.get(widgetContext.servicesMap.get('assetService'));
      deleteObservable = assetService.deleteAsset(entityId.id);
      break;
    case 'ENTITY_VIEW':
      let entityViewService = $injector.get(widgetContext.servicesMap.get('entityViewService'));
      deleteObservable = entityViewService.deleteEntityView(entityId.id);
      break;
    case 'EDGE':
      let edgeService = $injector.get(widgetContext.servicesMap.get('edgeService'));
      deleteObservable = edgeService.deleteEdge(entityId.id);
      break;
    case 'TENANT':
      let tenantService = $injector.get(widgetContext.servicesMap.get('tenantService'));
      deleteObservable = tenantService.deleteTenant(entityId.id);
      break;
    case 'CUSTOMER':
      let customerService = $injector.get(widgetContext.servicesMap.get('customerService'));
      deleteObservable = customerService.deleteCustomer(entityId.id);
      break;
    case 'DASHBOARD':
      let dashboardService = $injector.get(widgetContext.servicesMap.get('dashboardService'));
      deleteObservable = dashboardService.deleteDashboard(entityId.id);
      break;
    case 'USER':
      let userService = $injector.get(widgetContext.servicesMap.get('userService'));
      deleteObservable = userService.deleteUser(entityId.id);
      break;
    case 'SCHEDULER_EVENT':
      let schedulerEventService = $injector.get(widgetContext.servicesMap.get('schedulerEventService'));
      deleteObservable = schedulerEventService.deleteSchedulerEvent(entityId.id);
      break;
    case 'ROLE':
      let roleService = $injector.get(widgetContext.servicesMap.get('roleService'));
      deleteObservable = roleService.deleteRole(entityId.id);
      break;
    case 'ENTITY_GROUP':
      let entityGroupService = $injector.get(widgetContext.servicesMap.get('entityGroupService'));
      deleteObservable = entityGroupService.deleteEntityGroup(entityId.id);
      break;
    default:
      showErrorDialog(`Unsupported entity type '${entityId.entityType}'`);
      break;
  }
  if (deleteObservable) {
    deleteObservable.subscribe(
      function success() {
        widgetContext.updateAliases();
      },
      function fail() {
        showErrorDialog();
      }
    );
  }
}

function showErrorDialog(error) {
  let title = 'Error';
  error = error || 'Please try again.';
  let content = `An error occurred while deleting '${entityName}'. ${error}`;
  dialogs.alert(title, content, 'CLOSE').subscribe(
    function(result) {}
  );
}

